  1→import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
  2→import * as z from "zod";
  3→import {
  4→  completeTask,
  5→  createMemory,
  6→  createSessionCost,
  7→  createTaskExtended,
  8→  failTask,
  9→  getAgentById,
 10→  getDb,
 11→  getEpicWithProgress,
 12→  getLeadAgent,
 13→  getTaskById,
 14→  markEpicsProgressNotified,
 15→  updateAgentStatusFromCapacity,
 16→  updateMemoryEmbedding,
 17→  updateTaskProgress,
 18→} from "@/be/db";
 19→import { getEmbedding, serializeEmbedding } from "@/be/embedding";
 20→import { createToolRegistrar } from "@/tools/utils";
 21→import { AgentTaskSchema } from "@/types";
 22→
 23→// Schema for optional cost data that agents can self-report
 24→const CostDataSchema = z
 25→  .object({
 26→    totalCostUsd: z.number().min(0).describe("Total cost in USD"),
 27→    inputTokens: z.number().int().min(0).optional().describe("Input tokens used"),
 28→    outputTokens: z.number().int().min(0).optional().describe("Output tokens used"),
 29→    cacheReadTokens: z.number().int().min(0).optional().describe("Cache read tokens"),
 30→    cacheWriteTokens: z.number().int().min(0).optional().describe("Cache write tokens"),
 31→    durationMs: z.number().int().min(0).optional().describe("Duration in milliseconds"),
 32→    numTurns: z.number().int().min(1).optional().describe("Number of turns/iterations"),
 33→    model: z.string().optional().describe("Model used (e.g., 'opus', 'sonnet')"),
 34→  })
 35→  .describe("Optional cost data for tracking session costs");
 36→
 37→export const registerStoreProgressTool = (server: McpServer) => {
 38→  createToolRegistrar(server)(
 39→    "store-progress",
 40→    {
 41→      title: "Store task progress",
 42→      description:
 43→        "Stores the progress of a specific task. Can also mark task as completed or failed, which will set the agent back to idle.",
 44→      annotations: { idempotentHint: true },
 45→
 46→      inputSchema: z.object({
 47→        taskId: z.uuid().describe("The ID of the task to update progress for."),
 48→        progress: z.string().optional().describe("The progress update to store."),
 49→        status: z
 50→          .enum(["completed", "failed"])
 51→          .optional()
 52→          .describe("Set to 'completed' or 'failed' to finish the task."),
 53→        output: z.string().optional().describe("The output of the task (used when completing)."),
 54→        failureReason: z
 55→          .string()
 56→          .optional()
 57→          .describe("The reason for failure (used when failing)."),
 58→        costData: CostDataSchema.optional().describe(
 59→          "Optional cost data for tracking session costs. When provided, a session cost record will be created linked to this task.",
 60→        ),
 61→      }),
 62→      outputSchema: z.object({
 63→        success: z.boolean(),
 64→        message: z.string(),
 65→        task: AgentTaskSchema.optional(),
 66→      }),
 67→    },
 68→    async ({ taskId, progress, status, output, failureReason, costData }, requestInfo, _meta) => {
 69→      if (!requestInfo.agentId) {
 70→        return {
 71→          content: [
 72→            {
 73→              type: "text",
 74→              text: 'Agent ID not found. The MCP client should define the "X-Agent-ID" header.',
 75→            },
 76→          ],
 77→          structuredContent: {
 78→            yourAgentId: requestInfo.agentId,
 79→            success: false,
 80→            message: 'Agent ID not found. The MCP client should define the "X-Agent-ID" header.',
 81→          },
 82→        };
 83→      }
 84→
 85→      const txn = getDb().transaction(() => {
 86→        const agent = getAgentById(requestInfo.agentId ?? "");
 87→
 88→        if (!agent) {
 89→          return {
 90→            success: false,
 91→            message: `Agent with ID "${requestInfo.agentId}" not found in the swarm, register before storing task progress.`,
 92→          };
 93→        }
 94→
 95→        const existingTask = getTaskById(taskId);
 96→
 97→        if (!existingTask) {
 98→          return {
 99→            success: false,
100→            message: `Task with ID "${taskId}" not found.`,
101→          };
102→        }
103→
104→        let updatedTask = existingTask;
105→        const isTerminal = ["completed", "failed", "cancelled"].includes(existingTask.status);
106→
107→        // Update progress if provided (with deduplication)
108→        // Skip for tasks already in a terminal state to prevent zombie revival
109→        if (progress && !isTerminal) {
110→          // Skip if same progress text was set within the last 5 minutes
111→          const isDuplicate =
112→            existingTask.progress === progress &&
113→            existingTask.lastUpdatedAt &&
114→            Date.now() - new Date(existingTask.lastUpdatedAt).getTime() < 5 * 60 * 1000;
115→
116→          if (!isDuplicate) {
117→            const result = updateTaskProgress(taskId, progress);
118→            if (result) updatedTask = result;
119→          }
120→        }
121→
122→        // Handle status change
123→        if (status === "completed") {
124→          const result = completeTask(taskId, output);
125→          if (result) {
126→            updatedTask = result;
127→            if (existingTask.agentId) {
128→              // Derive status from capacity instead of always setting idle
129→              updateAgentStatusFromCapacity(existingTask.agentId);
130→            }
131→          }
132→        } else if (status === "failed") {
133→          const result = failTask(taskId, failureReason ?? "Unknown failure");
134→          if (result) {
135→            updatedTask = result;
136→            if (existingTask.agentId) {
137→              // Derive status from capacity instead of always setting idle
138→              updateAgentStatusFromCapacity(existingTask.agentId);
139→            }
140→          }
141→        } else {
142→          // Progress update - ensure status reflects current load
143→          if (existingTask.agentId) {
144→            updateAgentStatusFromCapacity(existingTask.agentId);
145→          }
146→        }
147→
148→        // Store cost data if provided (agents can self-report costs)
149→        if (costData && requestInfo.agentId) {
150→          createSessionCost({
151→            sessionId: `mcp-${taskId}-${Date.now()}`, // Generate unique session ID for MCP-based tasks
152→            taskId,
153→            agentId: requestInfo.agentId,
154→            totalCostUsd: costData.totalCostUsd,
155→            inputTokens: costData.inputTokens ?? 0,
156→            outputTokens: costData.outputTokens ?? 0,
157→            cacheReadTokens: costData.cacheReadTokens ?? 0,
158→            cacheWriteTokens: costData.cacheWriteTokens ?? 0,
159→            durationMs: costData.durationMs ?? 0,
160→            numTurns: costData.numTurns ?? 1,
161→            model: costData.model ?? "unknown",
162→            isError: status === "failed",
163→          });
164→        }
165→
166→        return {
167→          success: true,
168→          message: status
169→            ? `Task "${taskId}" marked as ${status}.`
170→            : `Progress stored for task "${taskId}".`,
171→          task: updatedTask,
172→        };
173→      });
174→
175→      const result = txn();
176→
177→      // Index completed and failed tasks as memory (async, non-blocking)
178→      if ((status === "completed" || status === "failed") && result.success && result.task) {
179→        (async () => {
180→          try {
181→            const taskContent =
182→              status === "completed"
183→                ? `Task: ${result.task!.task}\n\nOutput:\n${output || "(no output)"}`
184→                : `Task: ${result.task!.task}\n\nFailure reason:\n${failureReason || "No reason provided"}\n\nThis task failed. Learn from this to avoid repeating the mistake.`;
185→
186→            // Skip indexing if there's truly no content
187→            if (taskContent.length < 30) return;
188→
189→            const memory = createMemory({
190→              agentId: requestInfo.agentId,
191→              content: taskContent,
192→              name: `Task: ${result.task!.task.slice(0, 80)}`,
193→              scope: "agent",
194→              source: "task_completion",
195→              sourceTaskId: taskId,
196→            });
197→            const embedding = await getEmbedding(taskContent);
198→            if (embedding) {
199→              updateMemoryEmbedding(memory.id, serializeEmbedding(embedding));
200→            }
201→
202→            // Auto-promote high-value completions to swarm memory (P3)
203→            // Epic-linked tasks are also promoted so workers on the same epic can see each other's learnings
204→            const shouldShareWithSwarm =
205→              status === "completed" &&
206→              (result.task!.taskType === "research" ||
207→                result.task!.tags?.includes("knowledge") ||
208→                result.task!.tags?.includes("shared") ||
209→                result.task!.epicId != null);
210→
211→            if (shouldShareWithSwarm) {
212→              try {
213→                const swarmMemory = createMemory({
214→                  agentId: requestInfo.agentId,
215→                  scope: "swarm",
216→                  name: `Shared: ${result.task!.task.slice(0, 80)}`,
217→                  content: `Task completed by agent ${requestInfo.agentId}:\n\n${taskContent}`,
218→                  source: "task_completion",
219→                  sourceTaskId: taskId,
220→                });
221→                const swarmEmbedding = await getEmbedding(taskContent);
222→                if (swarmEmbedding) {
223→                  updateMemoryEmbedding(swarmMemory.id, serializeEmbedding(swarmEmbedding));
224→                }
225→              } catch {
226→                // Non-blocking — swarm memory promotion failure is not critical
227→              }
228→            }
229→          } catch {
230→            // Non-blocking — task completion memory failure should not affect task status
231→          }
232→        })();
233→      }
234→
235→      // Create follow-up task for the lead when a worker task finishes.
236→      // This replaces the old poll-based tasks_finished trigger which was unreliable.
237→      if (status && result.success && result.task) {
238→        try {
239→          const taskAgent = getAgentById(result.task.agentId ?? "");
240→          // Only create follow-ups for worker tasks (not lead's own tasks)
241→          if (taskAgent && !taskAgent.isLead) {
242→            const leadAgent = getLeadAgent();
243→            if (leadAgent) {
244→              const agentName = taskAgent.name || result.task.agentId?.slice(0, 8) || "Unknown";
245→              const taskDesc = result.task.task.slice(0, 200);
246→
247→              let followUpDescription: string;
248→              if (status === "completed") {
249→                const outputSummary = output ? output.slice(0, 500) : "(no output)";
250→                followUpDescription = `Worker task completed — review needed.\n\nAgent: ${agentName}\nTask: "${taskDesc}"\n\nOutput:\n${outputSummary}${output && output.length > 500 ? "..." : ""}\n\nUse \`get-task-details\` with taskId "${taskId}" for full details.`;
251→              } else {
252→                const reason = failureReason || "(no reason given)";
253→                followUpDescription = `Worker task failed — action needed.\n\nAgent: ${agentName}\nTask: "${taskDesc}"\n\nFailure reason: ${reason}\n\nDecide whether to reassign, retry, or handle the failure. Use \`get-task-details\` with taskId "${taskId}" for full details.`;
254→              }
255→
256→              // Enrich follow-up with epic context if task belongs to an epic
257→              let epicContext = "";
258→              if (result.task.epicId) {
259→                const epic = getEpicWithProgress(result.task.epicId);
260→                if (epic) {
261→                  epicContext = `\n\n## Epic Context\n`;
262→                  epicContext += `**Epic:** ${epic.name}\n`;
263→                  epicContext += `**Goal:** ${epic.goal}\n`;
264→                  epicContext += `**Progress:** ${epic.progress}% (${epic.taskStats.completed}/${epic.taskStats.total} tasks)\n`;
