  // Recursive property validation (only for objects)
  if (
    schema.properties !== undefined &&
    typeof schema.properties === "object" &&
    schema.properties !== null &&
    typeof data === "object" &&
    data !== null
  ) {
    const props = schema.properties as Record<string, Record<string, unknown>>;
    const obj = data as Record<string, unknown>;
    for (const [key, subSchema] of Object.entries(props)) {
      if (key in obj) {
        validate(subSchema, obj[key], path ? `${path}.${key}` : key, errors);
      }
    }
  }
}

input.new_string:
  // Enum check
  if (Array.isArray(schema.enum)) {
    const allowed = schema.enum as unknown[];
    if (!allowed.some((v) => JSON.stringify(v) === JSON.stringify(data))) {
      errors.push(`${prefix}: value ${JSON.stringify(data)} not in enum [${allowed.map((v) => JSON.stringify(v)).join(", ")}]`);
      return;
    }
  }

  // Const check
  if ("const" in schema) {
    if (JSON.stringify(data) !== JSON.stringify(schema.const)) {
      errors.push(`${prefix}: value ${JSON.stringify(data)} does not match const ${JSON.stringify(schema.const)}`);
      return;
    }
  }

  // Recursive property validation (only for objects)
  if (
    schema.properties !== undefined &&
    typeof schema.properties === "object" &&
    schema.properties !== null &&
    typeof data === "object" &&
    data !== null
  ) {
    const props = schema.properties as Record<string, Record<string, unknown>>;
    const obj = data as Record<string, unknown>;
    for (const [key, subSchema] of Object.entries(props)) {
      if (key in obj) {
        validate(subSchema, obj[key], path ? `${path}.${key}` : key, errors);
      }
    }
  }

  // Items validation (for arrays)
  if (
    schema.items !== undefined &&
    typeof schema.items === "object" &&
    schema.items !== null &&
    Array.isArray(data)
  ) {
    const itemSchema = schema.items as Record<string, unknown>;
    for (let i = 0; i < data.length; i++) {
      validate(itemSchema, data[i], `${prefix}[${i}]`, errors);
    }
  }
}

