  id: z.string().uuid(),
  url: z.string().min(1),
  name: z.string().min(1).max(100),
  clonePath: z.string().min(1),
  defaultBranch: z.string().default("main"),
  autoClone: z.boolean().default(true),
  createdAt: z.string(),
  lastUpdatedAt: z.string(),
