export type SwarmRepo = z.infer<typeof SwarmRepoSchema>;

// ============================================================================
// Agent Memory Types (Persistent Memory System)
// ============================================================================

export const AgentMemoryScopeSchema = z.enum(["agent", "swarm"]);
export const AgentMemorySourceSchema = z.enum([
