  const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(" AND ")}` : "";
  const query = `SELECT COUNT(*) as count FROM agent_tasks ${whereClause}`;

  const result = getDb()
    .prepare<{ count: number }, (string | AgentTaskStatus)[]>(query)
    .get(...params);

