        in_progress: number;
        paused: number;
        completed: number;
        failed: number;
      },
      []
    >(
      `SELECT
        COUNT(*) as total,
        SUM(CASE WHEN status = 'unassigned' THEN 1 ELSE 0 END) as unassigned,
