       VALUES (?, ?, ?, ?, ?, ?, ?, ?) RETURNING *`,
    )
    .get(
      id,
      data.url,
      data.name,
      clonePath,
      data.defaultBranch ?? "main",
      data.autoClone !== false ? 1 : 0,
      now,
      now,
    );

  if (!row) throw new Error("Failed to create repo");
  return rowToSwarmRepo(row);
