export function createWorkflow(data: {
  name: string;
  description?: string;
  definition: WorkflowDefinition;
  triggers?: TriggerConfig[];
  cooldown?: CooldownConfig;
  input?: Record<string, InputValue>;
  triggerSchema?: Record<string, unknown>;
