    } catch {}
    try {
      import("../workflows/event-bus").then(({ workflowEventBus }) => {
        workflowEventBus.emit("task.progress", {
          taskId: id,
          progress,
          agentId: row.agentId,
        });
      });
    } catch {}
  }
  return row ? rowToAgentTask(row) : null;
}

