886→function buildPromptForTrigger(
887→  trigger: Trigger,
888→  defaultPrompt: string,
889→  fmt: (cmd: string) => string = (cmd) => `/${cmd}`,
890→): string {
891→  switch (trigger.type) {
892→    case "task_assigned": {
893→      // Use the work-on-task command with task ID and description
894→      const taskDesc =
895→        trigger.task && typeof trigger.task === "object" && "task" in trigger.task
896→          ? (trigger.task as { task: string }).task
897→          : null;
898→      let prompt = `${fmt("work-on-task")} ${trigger.taskId}`;
899→      if (taskDesc) {
900→        prompt += `\n\nTask: "${taskDesc}"`;
901→      }
902→      prompt += `\n\nWhen done, use \`store-progress\` with status: "completed" and include your output.`;
903→      return prompt;
904→    }
905→
906→    case "task_offered": {
907→      // Use the review-offered-task command with context
908→      const taskDesc =
909→        trigger.task && typeof trigger.task === "object" && "task" in trigger.task
910→          ? (trigger.task as { task: string }).task
911→          : null;
912→      let prompt = `${fmt("review-offered-task")} ${trigger.taskId}`;
913→      if (taskDesc) {
914→        prompt += `\n\nA task has been offered to you:\n"${taskDesc}"`;
915→      }
916→      prompt += `\n\nAccept if you have capacity and skills. Reject with a reason if you cannot handle it.`;
917→      return prompt;
918→    }
919→
920→    case "unread_mentions":
921→      // Check messages - numbered steps for clarity
922→      return `You have ${trigger.count || "unread"} mention(s) in chat channels.
923→
924→1. Use \`read-messages\` with unreadOnly: true to see them
925→2. Respond to questions or requests directed at you
926→3. If a message requires work, create a task using \`send-task\``;
927→
928→    case "pool_tasks_available":
929→      // Worker: claim a task from the pool - numbered steps for clarity
930→      return `${trigger.count} task(s) available in the pool.
931→
932→1. Run \`get-tasks\` with unassigned: true to browse
933→2. Pick one matching your skills
934→3. Run \`task-action\` with action: "claim" and taskId: "<id>"
