      body.output = fallback.output;
    } else if (fallback?.failReason) {
      status = "failed";
      body.status = "failed";
      body.failureReason = fallback.failReason;
    } else {
      body.output =
        "Process completed (runner wrapper fallback - agent may have provided explicit output)";
    }
